class QueryBuilder:
    def __init__(self):
        self._table = ''
        self._where = []
    def table(self, name):
        self._table = name
        return self
    def where(self, condition):
        self._where.append(condition)
        return self
    def build(self):
        sql = f"SELECT * FROM {self._table}"
        if self._where:
            sql += " WHERE " + " AND ".join(self._where)
        return sql

