# Simple pipe function
def pipe(value, *functions):
    """Pass value through a sequence of functions."""
    return reduce(lambda v, f: f(v), functions, value)

# Usage
def double(x):
    return x * 2

def add_ten(x):
    return x + 10

def to_string(x):
    return f"Result: {x}"

result = pipe(5, double, add_ten, to_string)
print(result)  # "Result: 20"

# Compared to nested calls (reads inside-out)
result = to_string(add_ten(double(5)))
print(result)  # "Result: 20" -- same but harder to read

# Data processing pipeline
def strip_whitespace(text):
    return text.strip()

def lowercase(text):
    return text.lower()

def remove_punctuation(text):
    import string
    return text.translate(str.maketrans('', '', string.punctuation))

def split_words(text):
    return text.split()

words = pipe(
    "  Hello, World! This is a TEST.  ",
    strip_whitespace,
    lowercase,
    remove_punctuation,
    split_words
)
print(words)  # ['hello', 'world', 'this', 'is', 'a', 'test']

# Pipe with lambdas for parameterized functions
from functools import partial

def filter_by(items, predicate):
    return [x for x in items if predicate(x)]

def sort_by(items, key=None, reverse=False):
    return sorted(items, key=key, reverse=reverse)

def take(items, n):
    return items[:n]

numbers = [3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5]

result = pipe(
    numbers,
    lambda x: filter_by(x, lambda n: n > 2),
    lambda x: sort_by(x, reverse=True),
    lambda x: take(x, 5),
)
print(result)  # [9, 6, 5, 5, 5]

# Using partial for cleaner syntax
result = pipe(
    numbers,
    partial(filter_by, predicate=lambda n: n > 2),
    partial(sort_by, reverse=True),
    partial(take, n=5),
)
print(result)  # [9, 6, 5, 5, 5]

# Composing functions (create reusable pipeline)
def compose(*functions):
    """Create a function that applies functions right-to-left."""
    return reduce(lambda f, g: lambda x: f(g(x)), functions)

process_text = compose(split_words, remove_punctuation, lowercase, strip_whitespace)
result = process_text("  Hello, World!  ")
print(result)  # ['hello', 'world']

# Pipeline class for OOP style
class Pipeline:
    def __init__(self, value):
        self._value = value

    def pipe(self, func, *args, **kwargs):
        self._value = func(self._value, *args, **kwargs)
        return self

    @property
    def value(self):
        return self._value

result = (Pipeline("  Hello World!  ")
    .pipe(str.strip)
    .pipe(str.lower)
    .pipe(str.replace, 'world', 'python')
    .value)
print(result)  # 'hello python!'

