from typing import Optional, List, Any

# Strategy 1: Collect errors, fail at terminal
class FormBuilder:
    def __init__(self):
        self._data = {}
        self._errors: List[str] = []

    def field(self, name: str, value: Any, required: bool = False):
        if required and (value is None or value == ''):
            self._errors.append(f'{name} is required')
        else:
            self._data[name] = value
        return self

    def validate_email(self, field: str):
        value = self._data.get(field, '')
        if value and '@' not in value:
            self._errors.append(f'{field} is not a valid email')
        return self

    def build(self) -> dict:
        if self._errors:
            raise ValueError(f"Validation errors: {'; '.join(self._errors)}")
        return self._data

    @property
    def errors(self) -> List[str]:
        return self._errors

# Usage
try:
    result = (FormBuilder()
        .field('name', '', required=True)
        .field('email', 'bad-email', required=True)
        .validate_email('email')
        .build())
except ValueError as e:
    print(e)  # Validation errors: name is required; email is not a valid email

# Strategy 2: Result type (monadic error handling)
class Result:
    def __init__(self, value=None, error=None):
        self._value = value
        self._error = error

    @staticmethod
    def ok(value):
        return Result(value=value)

    @staticmethod
    def fail(error):
        return Result(error=error)

    @property
    def is_ok(self):
        return self._error is None

    @property
    def value(self):
        if not self.is_ok:
            raise ValueError(f"Cannot get value from error result: {self._error}")
        return self._value

    @property
    def error(self):
        return self._error

    def map(self, func):
        """Apply func if ok, skip if error."""
        if not self.is_ok:
            return self  # propagate error
        try:
            return Result.ok(func(self._value))
        except Exception as e:
            return Result.fail(str(e))

    def flat_map(self, func):
        """Apply func that returns Result."""
        if not self.is_ok:
            return self
        return func(self._value)

# Usage: errors propagate through the chain
def parse_int(s):
    return int(s)

def double(n):
    return n * 2

def check_positive(n):
    if n <= 0:
        raise ValueError('Must be positive')
    return n

# Success case
result = Result.ok('42').map(parse_int).map(check_positive).map(double)
print(f"Success: {result.value}")  # 84

# Error case -- error propagates, later steps skipped
result = Result.ok('abc').map(parse_int).map(check_positive).map(double)
print(f"Error: {result.error}")  # "invalid literal for int()..."

# Error in middle -- later steps skipped
result = Result.ok('-5').map(parse_int).map(check_positive).map(double)
print(f"Error: {result.error}")  # "Must be positive"

# Strategy 3: Debug helper for long chains
def debug(label=''):
    def _debug(value):
        print(f"[{label}] {type(value).__name__}: {value!r}")
        return value
    return _debug

result = (Result.ok('  42  ')
    .map(str.strip)
    .map(debug('after strip'))   # prints for debugging
    .map(parse_int)
    .map(debug('after parse'))   # prints for debugging
    .map(double))
print(result.value)  # 84

class Result:
    def __init__(self, value=None, error=None):
        self.value, self.error = value, error
        self.is_ok = error is None
    def map(self, func):
        if not self.is_ok:
            return self  # skip on error
        try:
            return Result(value=func(self.value))
        except Exception as e:
            return Result(error=str(e))

result = Result(value='42').map(int).map(lambda x: x*2)
print(result.value)  # 84

from abc import ABC, abstractmethod
from typing import Any

# Command interface
class Command(ABC):
    @abstractmethod
    def execute(self) -> None:
        pass

    @abstractmethod
    def undo(self) -> None:
        pass

    @abstractmethod
    def description(self) -> str:
        pass

# Concrete commands
class SetValueCommand(Command):
    def __init__(self, document: dict, key: str, value: Any):
        self._doc = document
        self._key = key
        self._new_value = value
        self._old_value = document.get(key)

    def execute(self):
        self._old_value = self._doc.get(self._key)
        self._doc[self._key] = self._new_value

    def undo(self):
        if self._old_value is None:
            self._doc.pop(self._key, None)
        else:
            self._doc[self._key] = self._old_value

    def description(self):
        return f"Set {self._key} = {self._new_value!r}"

class DeleteKeyCommand(Command):
    def __init__(self, document: dict, key: str):
        self._doc = document
        self._key = key
        self._old_value = None

    def execute(self):
        self._old_value = self._doc.pop(self._key, None)

    def undo(self):
        if self._old_value is not None:
            self._doc[self._key] = self._old_value

    def description(self):
        return f"Delete {self._key}"

# Command history with chainable API
class CommandHistory:
    def __init__(self, target: dict):
        self._target = target
        self._history: list[Command] = []
        self._redo_stack: list[Command] = []

    def set(self, key: str, value: Any) -> 'CommandHistory':
        cmd = SetValueCommand(self._target, key, value)
        cmd.execute()
        self._history.append(cmd)
        self._redo_stack.clear()  # clear redo after new action
        return self

    def delete(self, key: str) -> 'CommandHistory':
        cmd = DeleteKeyCommand(self._target, key)
        cmd.execute()
        self._history.append(cmd)
        self._redo_stack.clear()
        return self

    def undo(self) -> 'CommandHistory':
        if not self._history:
            print("Nothing to undo")
            return self
        cmd = self._history.pop()
        cmd.undo()
        self._redo_stack.append(cmd)
        print(f"Undo: {cmd.description()}")
        return self

    def redo(self) -> 'CommandHistory':
        if not self._redo_stack:
            print("Nothing to redo")
            return self
        cmd = self._redo_stack.pop()
        cmd.execute()
        self._history.append(cmd)
        print(f"Redo: {cmd.description()}")
        return self

    def show_history(self) -> 'CommandHistory':
        print("History:")
        for i, cmd in enumerate(self._history, 1):
            print(f"  {i}. {cmd.description()}")
        return self

    @property
    def state(self) -> dict:
        return dict(self._target)

# Usage with chaining
doc = {}
result = (CommandHistory(doc)
    .set('name', 'Alice')
    .set('email', 'alice@example.com')
    .set('role', 'admin')
    .show_history()
    .undo()            # undo role=admin
    .undo()            # undo email
    .show_history()
    .redo()            # redo email
    .set('age', 30)
    .show_history())

print(f"Final state: {result.state}")
# {'name': 'Alice', 'email': 'alice@example.com', 'age': 30}

# Batch operations
print("\n--- Batch undo ---")
(CommandHistory({'x': 1})
    .set('a', 10)
    .set('b', 20)
    .set('c', 30)
    .undo()
    .undo()
    .undo())

class History:
    def __init__(self):
        self._stack = []
    def do(self, action, undo_action):
        action()
        self._stack.append(undo_action)
        return self
    def undo(self):
        if self._stack:
            self._stack.pop()()
        return self
